export async function getRawProcessedAsync() {
    await delay();

    const valuesA = getRawValuesA();
    const valuesC = getRawValuesC();
    const valuesG = getRawValuesG();
    const valuesT = getRawValuesT();

    const timeStepMs = 250;

    return {
        valuesA, valuesC, valuesG, valuesT,
        peaksExitTimes: [], peaksNames: [], peaksQualities: [],
        timeStepMs
    };
}

